const response = $input.item.json.choices[0].message.content;
let outline;

try {
  outline = JSON.parse(response);
} catch (e) {
  const jsonMatch = response.match(/```json\s*([\s\S]*?)\s*```/);
  if (jsonMatch) {
    outline = JSON.parse(jsonMatch[1]);
  } else {
    const jsonMatch2 = response.match(/\{[\s\S]*\}/);
    if (jsonMatch2) {
      outline = JSON.parse(jsonMatch2[0]);
    } else {
      throw new Error("Could not parse outline response as JSON: " + response.substring(0, 200));
    }
  }
}

const originalInput = $('Build Outline Request').first().json;
const topic = originalInput.topic;
const video_name = originalInput.video_name;
const voice_id = originalInput.voice_id;
const script_type = originalInput.script_type;

return outline.sections.map((section, index) => ({
  json: {
    topic: topic,
    video_name: video_name,
    voice_id: voice_id,
    script_type: script_type,
    full_title: outline.title,
    hook_question: outline.hook_question,
    total_sections: outline.sections.length,
    full_outline: outline.sections,
    current_section: section,
    section_index: index,
    is_opening: section.number === 1,
    is_final: section.number === outline.sections.length
  }
}));

const sectionContent = $input.item.json.choices[0].message.content;
const loopData = $('Loop Over Sections').item.json;

const staticData = $getWorkflowStaticData('global');

// Extract the first sentence/opening phrase (first 50 chars or until first period)
const openingPhrase = sectionContent.substring(0, 100).split('.')[0];

// Initialize or append to used openings list
if (!staticData.usedOpenings) {
  staticData.usedOpenings = [];
}
staticData.usedOpenings.push(openingPhrase);

// Save content for next iteration
staticData.lastSectionContent = sectionContent;
staticData.lastSectionNumber = loopData.current_section.number;

// Format the section with header
const formattedSection = `# **Section ${loopData.current_section.number}: ${loopData.current_section.title}**\n\n${sectionContent}`;

return [{
  json: {
    topic: loopData.topic,
    video_name: loopData.video_name,
    voice_id: loopData.voice_id,
    full_title: loopData.full_title,
    total_sections: loopData.total_sections,
    section_number: loopData.current_section.number,
    section_title: loopData.current_section.title,
    section_content: formattedSection,
    raw_content: sectionContent,
    word_count: sectionContent.split(/\s+/).length
  }
}];

const sections = $input.item.json.all_sections;

// Sort by section number to ensure correct order
sections.sort((a, b) => a.section_number - b.section_number);

// Combine all sections with separator
const fullScript = sections.map(s => s.section_content).join('\n\n---\n\n');

// Calculate total word count
const totalWords = sections.reduce((sum, s) => sum + s.word_count, 0);

// Get metadata from first section
const metadata = sections[0];

return [{
  json: {
    topic: metadata.topic,
    video_name: metadata.video_name,
    voice_id: metadata.voice_id,
    full_title: metadata.full_title,
    total_sections: metadata.total_sections,
    total_words: totalWords,
    full_script: fullScript,
    sections: sections
  }
}];

// Clear staticData from any previous workflow runs
const staticData = $getWorkflowStaticData('global');
staticData.lastSectionContent = null;
staticData.lastSectionNumber = null;
staticData.usedOpenings = [];

// Pass through all input data unchanged
return $input.all();

const row = $input.item.json;

return [{
  json: {
    topic: row.topic,
    video_name: row.video_name,
    target_words: parseInt(row.target_words),
    voice_id: row.voice_id || 'AeRdCCKzvd23BpJoofzx', // default if empty
    script_type: row.script_type || 'deep_dive',
    // Preserve original row data for later update
    _original_row: row
  }
}];
